class PaymentTransaction {
  final String transactionId;
  final String userId;
  final double amount;
  final String currency;
  final PaymentMethod paymentMethod;
  final PaymentStatus status;
  final TransactionType type;
  final DateTime createdAt;
  final DateTime? completedAt;
  final String? gatewayTransactionId;
  final String? errorMessage;
  final Map<String, dynamic> metadata;
  final String? receiptData;
  final String checksum;

  PaymentTransaction({
    String? transactionId,
    required this.userId,
    required this.amount,
    this.currency = 'USD',
    required this.paymentMethod,
    this.status = PaymentStatus.pending,
    required this.type,
    DateTime? createdAt,
    this.completedAt,
    this.gatewayTransactionId,
    this.errorMessage,
    this.metadata = const {},
    this.receiptData,
    String? checksum,
  })  : transactionId = transactionId ?? const Uuid().v4(),
        createdAt = createdAt ?? DateTime.now(),
        checksum = checksum ?? _generateChecksum(
          transactionId ?? '',
          userId,
          amount,
          currency,
        );

  static String _generateChecksum(
    String txId,
    String userId,
    double amount,
    String currency,
  ) {
    final data = '$txId|$userId|$amount|$currency|${DateTime.now().millisecondsSinceEpoch}';
    return sha256.convert(utf8.encode(data)).toString();
  }

  PaymentTransaction copyWith({
    PaymentStatus? status,
    DateTime? completedAt,
    String? gatewayTransactionId,
    String? errorMessage,
    Map<String, dynamic>? metadata,
    String? receiptData,
  }) {
    return PaymentTransaction(
      transactionId: transactionId,
      userId: userId,
      amount: amount,
      currency: currency,
      paymentMethod: paymentMethod,
      status: status ?? this.status,
      type: type,
      createdAt: createdAt,
      completedAt: completedAt ?? this.completedAt,
      gatewayTransactionId: gatewayTransactionId ?? this.gatewayTransactionId,
      errorMessage: errorMessage ?? this.errorMessage,
      metadata: metadata ?? this.metadata,
      receiptData: receiptData ?? this.receiptData,
      checksum: checksum,
    );
  }

  Map<String, dynamic> toJson() => {
        'transactionId': transactionId,
        'userId': userId,
        'amount': amount,
        'currency': currency,
        'paymentMethod': paymentMethod.name,
        'status': status.name,
        'type': type.name,
        'createdAt': createdAt.toIso8601String(),
        'completedAt': completedAt?.toIso8601String(),
        'gatewayTransactionId': gatewayTransactionId,
        'errorMessage': errorMessage,
        'metadata': metadata,
        'checksum': checksum,
      };

  factory PaymentTransaction.fromJson(Map<String, dynamic> json) {
    return PaymentTransaction(
      transactionId: json['transactionId'],
      userId: json['userId'],
      amount: (json['amount'] as num).toDouble(),
      currency: json['currency'] ?? 'USD',
      paymentMethod: PaymentMethod.values.byName(json['paymentMethod']),
      status: PaymentStatus.values.byName(json['status']),
      type: TransactionType.values.byName(json['type']),
      createdAt: DateTime.parse(json['createdAt']),
      completedAt: json['completedAt'] != null ? DateTime.parse(json['completedAt']) : null,
      gatewayTransactionId: json['gatewayTransactionId'],
      errorMessage: json['errorMessage'],
      metadata: Map<String, dynamic>.from(json['metadata'] ?? {}),
      checksum: json['checksum'],
    );
  }
}

