class SecurePaymentStorage {
  static const _storage = FlutterSecureStorage(
    aOptions: AndroidOptions(encryptedSharedPreferences: true),
    iOptions: IOSOptions(accessibility: KeychainAccessibility.first_unlock_this_device),
  );

  static const _tokenPrefix = 'payment_token_';
  static const _cardPrefix = 'saved_card_';
  static const _txLogPrefix = 'tx_log_';

  Future<void> storeToken(String key, String token) async {
    final encryptedKey = _tokenPrefix + _hashKey(key);
    await _storage.write(key: encryptedKey, value: token);
  }

  Future<String?> retrieveToken(String key) async {
    final encryptedKey = _tokenPrefix + _hashKey(key);
    return await _storage.read(key: encryptedKey);
  }

  Future<void> deleteToken(String key) async {
    final encryptedKey = _tokenPrefix + _hashKey(key);
    await _storage.delete(key: encryptedKey);
  }

  Future<void> storeCardToken(String userId, CardDetails card) async {
    final key = '$_cardPrefix${userId}_${card.lastFour}';
    await _storage.write(key: key, value: jsonEncode(card.toJson()));
  }

  Future<List<CardDetails>> getSavedCards(String userId) async {
    final allKeys = await _storage.readAll();
    final cards = <CardDetails>[];
    for (final entry in allKeys.entries) {
      if (entry.key.startsWith('$_cardPrefix${userId}_')) {
        try {
          final json = jsonDecode(entry.value);
          cards.add(CardDetails(
            tokenizedNumber: json['tokenizedNumber'],
            brand: CardBrand.values.byName(json['brand']),
            lastFour: json['lastFour'],
            expiryMonth: json['expiryMonth'],
            expiryYear: json['expiryYear'],
            cardholderName: json['cardholderName'],
            fingerprint: json['fingerprint'],
          ));
        } catch (_) {}
      }
    }
    return cards;
  }

  Future<void> logTransaction(PaymentTransaction tx) async {
    final key = '$_txLogPrefix${tx.transactionId}';
    await _storage.write(key: key, value: jsonEncode(tx.toJson()));
  }

  Future<void> clearAllPaymentData() async {
    final allKeys = await _storage.readAll();
    for (final key in allKeys.keys) {
      if (key.startsWith(_tokenPrefix) ||
          key.startsWith(_cardPrefix) ||
          key.startsWith(_txLogPrefix)) {
        await _storage.delete(key: key);
      }
    }
  }

  String _hashKey(String input) {
    return sha256.convert(utf8.encode(input)).toString().substring(0, 16);
  }
}

