class PCIComplianceManager {
  static final PCIComplianceManager _instance = PCIComplianceManager._();
  factory PCIComplianceManager() => _instance;
  PCIComplianceManager._();

  final List<String> _auditLog = [];
  bool _isInitialized = false;

  void initialize() {
    _isInitialized = true;
    _logAudit('PCI Compliance Manager initialized');
  }

  /// Validate card number using Luhn algorithm (only for validation, never store)
  bool validateCardNumber(String cardNumber) {
    _ensureInitialized();
    final cleaned = cardNumber.replaceAll(RegExp(r'\s|-'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;
    if (!RegExp(r'^[0-9]+$').hasMatch(cleaned)) return false;
    return _luhnCheck(cleaned);
  }

  bool _luhnCheck(String number) {
    int sum = 0;
    bool alternate = false;
    for (int i = number.length - 1; i >= 0; i--) {
      int n = int.parse(number[i]);
      if (alternate) {
        n *= 2;
        if (n > 9) n -= 9;
      }
      sum += n;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  /// Validate CVV format (never store CVV)
  bool validateCVV(String cvv, CardBrand brand) {
    _ensureInitialized();
    final expectedLength = brand == CardBrand.amex ? 4 : 3;
    return cvv.length == expectedLength && RegExp(r'^[0-9]+$').hasMatch(cvv);
  }

  /// Validate expiry date
  bool validateExpiry(int month, int year) {
    if (month < 1 || month > 12) return false;
    final expiry = DateTime(year, month + 1, 0);
    return expiry.isAfter(DateTime.now());
  }

  /// Mask card number for display (PCI compliant)
  String maskCardNumber(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s|-'), '');
    if (cleaned.length < 4) return '****';
    return '**** **** **** ${cleaned.substring(cleaned.length - 4)}';
  }

  /// Detect card brand from number prefix
  CardBrand detectCardBrand(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s|-'), '');
    if (cleaned.startsWith('4')) return CardBrand.visa;
    if (RegExp(r'^5[1-5]').hasMatch(cleaned) || RegExp(r'^2[2-7]').hasMatch(cleaned)) {
      return CardBrand.mastercard;
    }
    if (cleaned.startsWith('34') || cleaned.startsWith('37')) return CardBrand.amex;
    if (cleaned.startsWith('6011') || cleaned.startsWith('65')) return CardBrand.discover;
    return CardBrand.unknown;
  }

  /// Sanitize input to prevent injection attacks
  String sanitizeInput(String input) {
    return input
        .replaceAll(RegExp(r'[<>"\x27;]'), '')
        .replaceAll(RegExp(r'\s+'), ' ')
        .trim();
  }

  /// Verify transaction integrity
  bool verifyTransactionIntegrity(PaymentTransaction transaction) {
    _ensureInitialized();
    // Verify amount is positive and reasonable
    if (transaction.amount <= 0 || transaction.amount > 999999.99) return false;
    // Verify required fields
    if (transaction.userId.isEmpty || transaction.transactionId.isEmpty) return false;
    _logAudit('Transaction integrity verified: ${transaction.transactionId}');
    return true;
  }

  /// Enforce transaction rate limiting
  final Map<String, List<DateTime>> _transactionHistory = {};

  bool checkRateLimit(String userId, {int maxPerMinute = 5, int maxPerHour = 30}) {
    _ensureInitialized();
    final now = DateTime.now();
    _transactionHistory.putIfAbsent(userId, () => []);
    final history = _transactionHistory[userId]!;

    // Clean old entries
    history.removeWhere((time) => now.difference(time).inHours > 1);

    final lastMinute = history.where((t) => now.difference(t).inMinutes < 1).length;
    final lastHour = history.length;

    if (lastMinute >= maxPerMinute || lastHour >= maxPerHour) {
      _logAudit('Rate limit exceeded for user: $userId');
      return false;
    }

    history.add(now);
    return true;
  }

  void _logAudit(String message) {
    final entry = '[${DateTime.now().toIso8601String()}] $message';
    _auditLog.add(entry);
    debugPrint('PCI_AUDIT: $entry');
  }

  List<String> getAuditLog() => List.unmodifiable(_auditLog);

  void _ensureInitialized() {
    if (!_isInitialized) {
      throw const PCIComplianceException(
        message: 'PCI Compliance Manager not initialized',
      );
    }
  }
}

