abstract class PaymentGateway {
  Future<void> initialize(PaymentConfig config);
  Future<PaymentResult> processPayment(PaymentTransaction transaction);
  Future<PaymentResult> refundPayment(String transactionId, double amount);
  Future<String> tokenizeCard(String cardNumber, String cvv, int expMonth, int expYear);
  Future<PaymentResult> createSubscription(String userId, String planId, String paymentToken);
  Future<PaymentResult> cancelSubscription(String subscriptionId);
  Future<bool> verifyWebhookSignature(String payload, String signature);
  void dispose();
}

class StripePaymentGateway implements PaymentGateway {
  late PaymentConfig _config;
  bool _initialized = false;
  final PCIComplianceManager _pciManager = PCIComplianceManager();

  @override
  Future<void> initialize(PaymentConfig config) async {
    _config = config;
    // In production, initialize Stripe SDK here:
    // Stripe.publishableKey = config.stripePublishableKey;
    // await Stripe.instance.applySettings();
    _initialized = true;
    debugPrint('Stripe Gateway initialized in ${config.environment.name} mode');
  }

  @override
  Future<PaymentResult> processPayment(PaymentTransaction transaction) async {
    _ensureInitialized();

    if (!_pciManager.verifyTransactionIntegrity(transaction)) {
      return PaymentResult.failed('INTEGRITY_CHECK_FAILED', 'Transaction integrity check failed');
    }

    if (!_pciManager.checkRateLimit(transaction.userId)) {
      return PaymentResult.failed('RATE_LIMIT', 'Too many transactions. Please try again later.');
    }

    try {
      // In production, call Stripe API:
      // final paymentIntent = await Stripe.instance.createPaymentMethod(...)
      // final confirmed = await Stripe.instance.confirmPayment(...)

      // Simulate API call
      await Future.delayed(const Duration(seconds: 1));

      final gatewayTxId = 'pi_${const Uuid().v4().replaceAll('-', '').substring(0, 24)}';

      final completedTx = transaction.copyWith(
        status: PaymentStatus.completed,
        completedAt: DateTime.now(),
        gatewayTransactionId: gatewayTxId,
        metadata: {
          ...transaction.metadata,
          'gateway': 'stripe',
          'environment': _config.environment.name,
        },
      );

      return PaymentResult.successful(completedTx);
    } catch (e) {
      return PaymentResult.failed('STRIPE_ERROR', e.toString());
    }
  }

  @override
  Future<PaymentResult> refundPayment(String transactionId, double amount) async {
    _ensureInitialized();

    try {
      // In production: call Stripe refund API
      await Future.delayed(const Duration(milliseconds: 500));

      final refundTx = PaymentTransaction(
        userId: 'system',
        amount: amount,
        paymentMethod: PaymentMethod.creditCard,
        type: TransactionType.refund,
        status: PaymentStatus.completed,
        completedAt: DateTime.now(),
        gatewayTransactionId: 're_${const Uuid().v4().replaceAll('-', '').substring(0, 24)}',
        metadata: {'originalTransactionId': transactionId},
      );

      return PaymentResult.successful(refundTx);
    } catch (e) {
      return PaymentResult.failed('REFUND_FAILED', e.toString());
    }
  }

  @override
  Future<String> tokenizeCard(
    String cardNumber,
    String cvv,
    int expMonth,
    int expYear,
  ) async {
    _ensureInitialized();

    final brand = _pciManager.detectCardBrand(cardNumber);
    if (!_pciManager.validateCardNumber(cardNumber)) {
      throw const PaymentException(code: 'INVALID_CARD', message: 'Invalid card number');
    }
    if (!_pciManager.validateCVV(cvv, brand)) {
      throw const PaymentException(code: 'INVALID_CVV', message: 'Invalid CVV');
    }
    if (!_pciManager.validateExpiry(expMonth, expYear)) {
      throw const PaymentException(code: 'CARD_EXPIRED', message: 'Card is expired');
    }

    // In production: use Stripe.instance.createToken or PaymentMethod
    // NEVER send raw card data to your own server
    await Future.delayed(const Duration(milliseconds: 300));

    return 'tok_${const Uuid().v4().replaceAll('-', '').substring(0, 24)}';
  }

  @override
  Future<PaymentResult> createSubscription(
    String userId,
    String planId,
    String paymentToken,
  ) async {
    _ensureInitialized();

    try {
      await Future.delayed(const Duration(seconds: 1));

      final subTx = PaymentTransaction(
        userId: userId,
        amount: 0, // Amount determined by plan
        paymentMethod: PaymentMethod.creditCard,
        type: TransactionType.subscription,
        status: PaymentStatus.completed,
        completedAt: DateTime.now(),
        gatewayTransactionId: 'sub_${const Uuid().v4().replaceAll('-', '').substring(0, 24)}',
        metadata: {'planId': planId, 'paymentToken': paymentToken},
      );

      return PaymentResult.successful(subTx);
    } catch (e) {
      return PaymentResult.failed('SUBSCRIPTION_FAILED', e.toString());
    }
  }

  @override
  Future<PaymentResult> cancelSubscription(String subscriptionId) async {
    _ensureInitialized();

    try {
      await Future.delayed(const Duration(milliseconds: 500));

      final cancelTx = PaymentTransaction(
        userId: 'system',
        amount: 0,
        paymentMethod: PaymentMethod.creditCard,
        type: TransactionType.subscription,
        status: PaymentStatus.cancelled,
        completedAt: DateTime.now(),
        metadata: {'subscriptionId': subscriptionId, 'action': 'cancel'},
      );

      return PaymentResult.successful(cancelTx);
    } catch (e) {
      return PaymentResult.failed('CANCEL_FAILED', e.toString());
    }
  }

  @override
  Future<bool> verifyWebhookSignature(String payload, String signature) async {
    // In production: use Stripe webhook signature verification
    // stripe.webhooks.constructEvent(payload, signature, endpointSecret)
    final computed = sha256.convert(utf8.encode('$payload${_config.stripeSecretKey}')).toString();
    return computed.isNotEmpty; // Simplified for demo
  }

  @override
  void dispose() {
    _initialized = false;
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw const PaymentException(
        code: 'NOT_INITIALIZED',
        message: 'Stripe gateway not initialized',
      );
    }
  }
}

