      type: product.isSubscription ? TransactionType.subscription : TransactionType.purchase,
      status: PaymentStatus.completed,
      completedAt: DateTime.now(),
      metadata: {'productId': productId, 'platform': Platform.isIOS ? 'ios' : 'android'},
    );

    await _storage.logTransaction(tx);
    _purchaseController.add(PaymentResult.successful(tx));
  }

  Future<void> restorePurchases() async {
    if (!_available) return;
    // In production: await _iap.restorePurchases();
    debugPrint('Restoring purchases...');
  }

  Future<bool> verifyPurchaseReceipt(String receiptData) async {
    // In production: Send to your backend for server-side validation
    // iOS: Verify with Apple's verifyReceipt endpoint
    // Android: Verify with Google Play Developer API
    await Future.delayed(const Duration(milliseconds: 500));
    return receiptData.isNotEmpty;
  }

  void dispose() {
    _subscription?.cancel();
    _purchaseController.close();
  }
}

