// 7. MOBILE WALLET SERVICE (Apple Pay / Google Pay)
// ============================================================================

class MobileWalletService {
  late PaymentConfig _config;
  bool _initialized = false;

  Future<void> initialize(PaymentConfig config) async {
    _config = config;
    _initialized = true;
  }

  Future<bool> isApplePayAvailable() async {
    if (!Platform.isIOS) return false;
    // In production: use Pay plugin or PassKit to check
    return true;
  }

  Future<bool> isGooglePayAvailable() async {
    if (!Platform.isAndroid) return false;
    // In production: use Pay plugin or Google Pay API
    return true;
  }

  Future<bool> isWalletPayAvailable() async {
    if (Platform.isIOS) return isApplePayAvailable();
    if (Platform.isAndroid) return isGooglePayAvailable();
    return false;
  }

  Future<PaymentResult> processApplePay({
    required String userId,
    required double amount,
    required String description,
  }) async {
    _ensureInitialized();

    if (!Platform.isIOS) {
      return PaymentResult.failed('PLATFORM_ERROR', 'Apple Pay is only available on iOS');
    }

    try {
      // In production:
      // final paymentItems = [PaymentItem(label: description, amount: amount.toStringAsFixed(2))];
      // final result = await Pay.withAssets(['apple_pay_config.json']).showPaymentSelector(
      //   PayProvider.apple_pay, paymentItems);
      // Then tokenize through Stripe or your gateway

      await Future.delayed(const Duration(seconds: 1));

      final tx = PaymentTransaction(
        userId: userId,
        amount: amount,
        paymentMethod: PaymentMethod.applePay,
        type: TransactionType.purchase,
        status: PaymentStatus.completed,
        completedAt: DateTime.now(),
        gatewayTransactionId: 'ap_${const Uuid().v4().replaceAll('-', '').substring(0, 16)}',
        metadata: {'description': description, 'wallet': 'apple_pay'},
      );

      return PaymentResult.successful(tx);
    } catch (e) {
      return PaymentResult.failed('APPLE_PAY_ERROR', e.toString());
    }
  }

  Future<PaymentResult> processGooglePay({
    required String userId,
    required double amount,
    required String description,
  }) async {
    _ensureInitialized();

    if (!Platform.isAndroid) {
      return PaymentResult.failed('PLATFORM_ERROR', 'Google Pay is only available on Android');
    }

    try {
      // In production:
      // final paymentItems = [PaymentItem(label: description, amount: amount.toStringAsFixed(2))];
      // final result = await Pay.withAssets(['google_pay_config.json']).showPaymentSelector(
      //   PayProvider.google_pay, paymentItems);

      await Future.delayed(const Duration(seconds: 1));

      final tx = PaymentTransaction(
        userId: userId,
        amount: amount,
        paymentMethod: PaymentMethod.googlePay,
        type: TransactionType.purchase,
        status: PaymentStatus.completed,
        completedAt: DateTime.now(),
        gatewayTransactionId: 'gp_${const Uuid().v4().replaceAll('-', '').substring(0, 16)}',
        metadata: {'description': description, 'wallet': 'google_pay'},
      );

      return PaymentResult.successful(tx);
    } catch (e) {
      return PaymentResult.failed('GOOGLE_PAY_ERROR', e.toString());
    }
  }

  Future<PaymentResult> processWalletPay({
    required String userId,
    required double amount,
    required String description,
  }) async {
    if (Platform.isIOS) {
      return processApplePay(userId: userId, amount: amount, description: description);
    } else if (Platform.isAndroid) {
      return processGooglePay(userId: userId, amount: amount, description: description);
    }
    return PaymentResult.failed('UNSUPPORTED', 'Mobile wallet not supported on this platform');
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw const PaymentException(
        code: 'NOT_INITIALIZED',
        message: 'Wallet service not initialized',
      );
    }
  }

  void dispose() {
    _initialized = false;
  }
}

// ============================================================================
// 8. TRANSACTION MANAGER
// ============================================================================

class TransactionManager {
  final SecurePaymentStorage _storage = SecurePaymentStorage();
  final List<PaymentTransaction> _pendingTransactions = [];
  final _transactionStream = StreamController<PaymentTransaction>.broadcast();

  Stream<PaymentTransaction> get transactionUpdates => _transactionStream.stream;

  Future<void> recordTransaction(PaymentTransaction transaction) async {
    await _storage.logTransaction(transaction);
    _transactionStream.add(transaction);
    debugPrint('Transaction recorded: ${transaction.transactionId} - ${transaction.status.name}');
  }

  void addPendingTransaction(PaymentTransaction transaction) {
    _pendingTransactions.add(transaction);
  }

  void removePendingTransaction(String transactionId) {
    _pendingTransactions.removeWhere((t) => t.transactionId == transactionId);
  }

  List<PaymentTransaction> get pendingTransactions => List.unmodifiable(_pendingTransactions);

  /// Retry failed transactions with exponential backoff
  Future<PaymentResult> retryTransaction(
    PaymentTransaction transaction,
    PaymentGateway gateway, {
    int maxRetries = 3,
  }) async {
    int attempt = 0;
    PaymentResult? lastResult;

    while (attempt < maxRetries) {
      attempt++;
      final delay = Duration(seconds: (1 << attempt)); // exponential backoff
      await Future.delayed(delay);

      debugPrint('Retry attempt $attempt for transaction ${transaction.transactionId}');

      lastResult = await gateway.processPayment(transaction);
      if (lastResult.success) {
        await recordTransaction(lastResult.transaction!);
        return lastResult;
      }
    }

    return lastResult ?? PaymentResult.failed('RETRY_EXHAUSTED', 'All retry attempts failed');
  }

  /// Idempotency check
  Future<bool> isTransactionProcessed(String transactionId) async {
    // In production, check against backend/database
    return false;
  }

  void dispose() {
    _transactionStream.close();
  }
}

// ============================================================================
// 9. MAIN PAYMENT SERVICE (FACADE)
// ============================================================================

class PaymentService extends ChangeNotifier {
  late PaymentConfig _config;
  late PaymentGateway _gateway;
  late InAppPurchaseService _iapService;
  late MobileWalletService _walletService;
  late TransactionManager _transactionManager;
  late SecurePaymentStorage _storage;

  final PCIComplianceManager _pciManager = PCIComplianceManager();

  bool _initialized = false;
  bool _processing = false;
  PaymentTransaction? _currentTransaction;
  final List<PaymentTransaction> _transactionHistory = [];
  String? _lastError;

  // Getters
  bool get isInitialized => _initialized;
  bool get isProcessing => _processing;
  PaymentTransaction? get currentTransaction => _currentTransaction;
  List<PaymentTransaction> get transactionHistory => List.unmodifiable(_transactionHistory);
  String? get lastError => _lastError;
  InAppPurchaseService get iapService => _iapService;

  /// Initialize the payment service
  Future<void> initialize(PaymentConfig config) async {
    if (_initialized) return;

    _config = config;
    _storage = SecurePaymentStorage();
    _transactionManager = TransactionManager();
    _pciManager.initialize();

    // Initialize payment gateway
    _gateway = StripePaymentGateway();
    await _gateway.initialize(config);

    // Initialize IAP service
    _iapService = InAppPurchaseService();
    await _iapService.initialize();

    // Initialize wallet service
    _walletService = MobileWalletService();
    await _walletService.initialize(config);

    // Listen to IAP stream
    _iapService.purchaseStream.listen((result) {
      if (result.success && result.transaction != null) {
        _transactionHistory.add(result.transaction!);
        notifyListeners();
      }
    });

    // Listen to transaction updates
    _transactionManager.transactionUpdates.listen((tx) {
      _updateTransactionInHistory(tx);
      notifyListeners();
    });

    _initialized = true;
    notifyListeners();
    debugPrint('PaymentService initialized successfully');
  }

  /// Process a card payment
  Future<PaymentResult> processCardPayment({
    required String userId,
    required double amount,
    required String paymentToken,
    String? description,
    Map<String, dynamic>? metadata,
  }) async {
    _ensureInitialized();
    _setProcessing(true);

    try {
      if (amount <= 0) {
        return _handleError('INVALID_AMOUNT', 'Amount must be greater than zero');
      }

      if (!_pciManager.checkRateLimit(userId)) {
        return _handleError('RATE_LIMIT', 'Too many transactions. Please wait.');
      }

      final transaction = PaymentTransaction(
        userId: userId,
        amount: amount,
        currency: _config.currencyCode,
        paymentMethod: PaymentMethod.creditCard,
        type: TransactionType.purchase,
        metadata: {
          'paymentToken': paymentToken,
          'description': description ?? '',
          ...?metadata,
        },
      );

      _currentTransaction = transaction;
      notifyListeners();

      final result = await _gateway.processPayment(transaction);

      if (result.success && result.transaction != null) {
        await _transactionManager.recordTransaction(result.transaction!);
        _transactionHistory.add(result.transaction!);
        _currentTransaction = result.transaction;
      }

      return result;
    } catch (e) {
      return _handleError('PAYMENT_ERROR', e.toString());
    } finally {
      _setProcessing(false);
    }
  }

  /// Process wallet payment (Apple Pay / Google Pay)
  Future<PaymentResult> processWalletPayment({
    required String userId,
    required double amount,
    required String description,
  }) async {
    _ensureInitialized();
    _setProcessing(true);

    try {
      final result = await _walletService.processWalletPay(
        userId: userId,
        amount: amount,
        description: description,
      );

      if (result.success && result.transaction != null) {
        await _transactionManager.recordTransaction(result.transaction!);
        _transactionHistory.add(result.transaction!);
      }

      return result;
    } catch (e) {
      return _handleError('WALLET_ERROR', e.toString());
    } finally {
      _setProcessing(false);
    }
  }

  /// Process in-app purchase
  Future<void> purchaseProduct(String productId, String userId) async {
    _ensureInitialized();
    _setProcessing(true);

    try {
      await _iapService.purchaseProduct(productId, userId);
    } catch (e) {
      _lastError = e.toString();
      notifyListeners();
      rethrow;
    } finally {
      _setProcessing(false);
    }
  }

  /// Load available IAP products
  Future<List<InAppProduct>> loadProducts(Set<String> productIds) async {
    _ensureInitialized();
    return _iapService.loadProducts(productIds);
  }

  /// Restore purchases
  Future<void> restorePurchases() async {
    _ensureInitialized();
    await _iapService.restorePurchases();
  }

  /// Tokenize card (PCI compliant - sends directly to Stripe, never to your server)
  Future<String> tokenizeCard({
    required String cardNumber,
    required String cvv,
    required int expMonth,
    required int expYear,
  }) async {
    _ensureInitialized();
    return _gateway.tokenizeCard(cardNumber, cvv, expMonth, expYear);
  }

  /// Save card token for future use
  Future<void> saveCard(String userId, CardDetails card) async {
    _ensureInitialized();
    await _storage.storeCardToken(userId, card);
  }

  /// Get saved cards
  Future<List<CardDetails>> getSavedCards(String userId) async {
    _ensureInitialized();
    return _storage.getSavedCards(userId);
  }

  /// Process refund
  Future<PaymentResult> processRefund(String transactionId, double amount) async {
    _ensureInitialized();
    _setProcessing(true);

    try {
      final result = await _gateway.refundPayment(transactionId, amount);
      if (result.success && result.transaction != null) {
        await _transactionManager.recordTransaction(result.transaction!);
        _transactionHistory.add(result.transaction!);
      }
      return result;
    } catch (e) {
      return _handleError('REFUND_ERROR', e.toString());
    } finally {
      _setProcessing(false);
    }
  }

  /// Create subscription
  Future<PaymentResult> createSubscription({
    required String userId,
    required String planId,
    required String paymentToken,
  }) async {
    _ensureInitialized();
    _setProcessing(true);

    try {
      final result = await _gateway.createSubscription(userId, planId, paymentToken);
      if (result.success && result.transaction != null) {
        await _transactionManager.recordTransaction(result.transaction!);
        _transactionHistory.add(result.transaction!);
      }
      return result;
    } catch (e) {
      return _handleError('SUBSCRIPTION_ERROR', e.toString());
    } finally {
      _setProcessing(false);
    }
  }

  /// Cancel subscription
  Future<PaymentResult> cancelSubscription(String subscriptionId) async {
    _ensureInitialized();
    return _gateway.cancelSubscription(subscriptionId);
  }

  /// Check wallet availability
  Future<bool> isWalletPayAvailable() async {
    return _walletService.isWalletPayAvailable();
  }

  /// Validate card details (client-side only, PCI compliant)
  Map<String, bool> validateCardDetails({
    required String cardNumber,
    required String cvv,
    required int expMonth,
    required int expYear,
  }) {
    final brand = _pciManager.detectCardBrand(cardNumber);
    return {
      'numberValid': _pciManager.validateCardNumber(cardNumber),
      'cvvValid': _pciManager.validateCVV(cvv, brand),
      'expiryValid': _pciManager.validateExpiry(expMonth, expYear),
    };
  }

  // Private helpers
  void _setProcessing(bool value) {
    _processing = value;
    notifyListeners();
  }

  PaymentResult _handleError(String code, String message) {
    _lastError = message;
    notifyListeners();
    return PaymentResult.failed(code, message);
  }

  void _updateTransactionInHistory(PaymentTransaction tx) {
    final index = _transactionHistory.indexWhere((t) => t.transactionId == tx.transactionId);
    if (index >= 0) {
      _transactionHistory[index] = tx;
    }
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw const PaymentException(
        code: 'NOT_INITIALIZED',
        message: 'PaymentService must be initialized before use',
      );
    }
  }

  @override
  void dispose() {
    _gateway.dispose();
    _iapService.dispose();
    _walletService.dispose();
    _transactionManager.dispose();
    super.dispose();
  }
}

