// --- Credit Card Input Form ---
class SecureCardInputForm extends StatefulWidget {
  final Function(String token) onTokenized;
  final Function(String error)? onError;
  final PaymentService paymentService;

  const SecureCardInputForm({
    super.key,
    required this.onTokenized,
    this.onError,
    required this.paymentService,
  });

  @override
  State<SecureCardInputForm> createState() => _SecureCardInputFormState();
}

class _SecureCardInputFormState extends State<SecureCardInputForm> {
  final _formKey = GlobalKey<FormState>();
  final _cardNumberController = TextEditingController();
  final _cvvController = TextEditingController();
  final _expiryController = TextEditingController();
  final _nameController = TextEditingController();
  final _pciManager = PCIComplianceManager();

  bool _isLoading = false;
  CardBrand _detectedBrand = CardBrand.unknown;

  @override
  void dispose() {
    // Securely clear sensitive data
    _cardNumberController.clear();
    _cvvController.clear();
    _expiryController.clear();
    _nameController.clear();
    _cardNumberController.dispose();
    _cvvController.dispose();
    _expiryController.dispose();
    _nameController.dispose();
    super.dispose();
  }

  Future<void> _tokenizeCard() async {
    if (!_formKey.currentState!.validate()) return;

    setState(() => _isLoading = true);

    try {
      final expiry = _expiryController.text.split('/');
      final expMonth = int.parse(expiry[0]);
      final expYear = int.parse('20${expiry[1]}');

      final token = await widget.paymentService.tokenizeCard(
        cardNumber: _cardNumberController.text.replaceAll(' ', ''),
        cvv: _cvvController.text,
        expMonth: expMonth,
        expYear: expYear,
      );

      // Clear sensitive data immediately after tokenization
      _cardNumberController.clear();
      _cvvController.clear();

      widget.onTokenized(token);
    } catch (e) {
      widget.onError?.call(e.toString());
    } finally {
      setState(() => _isLoading = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Form(
      key: _formKey,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // Card Number
          TextFormField(
            controller: _cardNumberController,
            decoration: InputDecoration(
              labelText: 'Card Number',
              hintText: '4242 4242 4242 4242',
              prefixIcon: const Icon(Icons.credit_card),
              suffixIcon: _buildCardBrandIcon(),
              border: const OutlineInputBorder(),
            ),
            keyboardType: TextInputType.number,
            maxLength: 19,
            onChanged: (value) {
              final cleaned = value.replaceAll(' ', '');
              setState(() {
                _detectedBrand = _pciManager.detectCardBrand(cleaned);
              });
            },
            validator: (value) {
              if (value == null || value.isEmpty) return 'Card number is required';
              final cleaned = value.replaceAll(' ', '');
              if (!_pciManager.validateCardNumber(cleaned)) return 'Invalid card number';
              return null;
            },
            // Prevent screenshots and screen recording for sensitive fields
            enableInteractiveSelection: false,
          ),
          const SizedBox(height: 16),

          // Expiry and CVV Row
          Row(
            children: [
              Expanded(
                child: TextFormField(
                  controller: _expiryController,
                  decoration: const InputDecoration(
                    labelText: 'Expiry',
                    hintText: 'MM/YY',
                    prefixIcon: Icon(Icons.calendar_today),
                    border: OutlineInputBorder(),
                  ),
                  keyboardType: TextInputType.number,
                  maxLength: 5,
                  validator: (value) {
                    if (value == null || value.isEmpty) return 'Required';
                    final parts = value.split('/');
                    if (parts.length != 2) return 'Use MM/YY';
                    try {
                      final month = int.parse(parts[0]);
                      final year = int.parse('20${parts[1]}');
                      if (!_pciManager.validateExpiry(month, year)) return 'Expired';
                    } catch (_) {
                      return 'Invalid';
                    }
                    return null;
                  },
                ),
              ),
              const SizedBox(width: 16),
              Expanded(
                child: TextFormField(
                  controller: _cvvController,
                  decoration: const InputDecoration(
                    labelText: 'CVV',
                    hintText: '123',
                    prefixIcon: Icon(Icons.lock),
                    border: OutlineInputBorder(),
                  ),
                  keyboardType: TextInputType.number,
                  maxLength: _detectedBrand == CardBrand.amex ? 4 : 3,
                  obscureText: true,
                  validator: (value) {
                    if (value == null || value.isEmpty) return 'Required';
                    if (!_pciManager.validateCVV(value, _detectedBrand)) return 'Invalid';
                    return null;
                  },
                ),
              ),
            ],
          ),
          const SizedBox(height: 16),

          // Cardholder Name
          TextFormField(
            controller: _nameController,
            decoration: const InputDecoration(
              labelText: 'Cardholder Name',
              hintText: 'John Doe',
              prefixIcon: Icon(Icons.person),
              border: OutlineInputBorder(),
            ),
            textCapitalization: TextCapitalization.words,
            validator: (value) {
              if (value == null || value.trim().isEmpty) return 'Name is required';
              return null;
            },
          ),
          const SizedBox(height: 24),

          // Submit Button
          SizedBox(
            height: 50,
            child: ElevatedButton(
              onPressed: _isLoading ? null : _tokenizeCard,
              style: ElevatedButton.styleFrom(
                backgroundColor: Theme.of(context).primaryColor,
                shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
              ),
              child: _isLoading
                  ? const SizedBox(
                      height: 24,
                      width: 24,
                      child: CircularProgressIndicator(color: Colors.white, strokeWidth: 2),
                    )
                  : const Text(
                      'Save Card',
                      style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold, color: Colors.white),
                    ),
            ),
          ),

          // Security notice
          const Padding(
            padding: EdgeInsets.only(top: 12),
            child: Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                Icon(Icons.lock, size: 14, color: Colors.grey),
                SizedBox(width: 4),
                Text(
                  'Card data is securely tokenized and never stored on device',
                  style: TextStyle(fontSize: 11, color: Colors.grey),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildCardBrandIcon() {
    IconData icon;
    Color color;

    switch (_detectedBrand) {
      case CardBrand.visa:
        icon = Icons.credit_card;
        color = Colors.blue;
        break;
      case CardBrand.mastercard:
        icon = Icons.credit_card;
        color = Colors.orange;
        break;
      case CardBrand.amex:
        icon = Icons.credit_card;
        color = Colors.green;
        break;
      case CardBrand.discover:
        icon = Icons.credit_card;
        color = Colors.purple;
        break;
      default:
        icon = Icons.credit_card;
        color = Colors.grey;
    }

    return Icon(icon, color: color);
  }
}

